DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "niceTables.pl",
  "PGchoicemacros.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "parserPopUp.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Fraction");
$actual_solution = Fraction(random_coprime([1..9],[2..9]));
($m, $n) = (2..9)[NchooseK(8,2)];
$b = Fraction(random_coprime([-9..-1,1..9],[2..9]));
$left = Formula("$m x + $b")->reduce;
$right = Formula("$n x");
$right += $left->eval(x => $actual_solution) - $right->eval(x => $actual_solution);
$right = $right->reduce;
$proposed_solution = random(0,1) ? $actual_solution : $actual_solution + non_zero_random(-3,3)/($actual_solution->value)[1];
Context("LimitedFraction")->flags->set(allowMixedNumbers => 0, showMixedNumbers => 0);
$lefteval = Fraction($left->eval(x => $proposed_solution));
$righteval = Fraction($right->eval(x => $proposed_solution));
$dropdown = DropDown(["Yes, it is a solution.", "No, it is not a solution."], ($lefteval == $righteval) ? 0 : 1, showInStatic => 0);
if ($lefteval == $righteval) {
  $sol[0] = "Since these are equal, ";
  $sol[1] = " is a solution to ";
} else {
  $sol[0] = "Since these are not equal,";
  $sol[1] = " is not a solution to ";
}

############################################################
# Body
############################################################

BEGIN_PGML
Check if the given number is a solution to the given equation.

Is [`[$proposed_solution]`] a solution to [`[$left]=[$right]\text{?}`]

>> [@DataTable(
  [
    [PGML('[`[$left->TeX]`]'),
     PGML('[`=`]'),
     PGML('[`[$right->TeX]`]'),
    ],
    [PGML('[_]{$lefteval}{3}'),
     PGML('[`\wonder{=}`]'),
     PGML('[_]{$righteval}{3}'),
    ],
  ],
      align => 'rcl',
      valign => 'middle',);@]* <<

[_]{$dropdown}{5}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
We have to substitute [`[$proposed_solution]`] in for [`x`] and simplify each side. The left side simplifies to [`[$lefteval]`] and the right side simplifies to [`[$righteval]\text{.}`] [$sol[0]] [`[$proposed_solution]`] [$sol[1]] [`[$left]=[$right]\text{.}`]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
